class BookMyShow {
    int n, m;
    List<int[]> rows;

    public BookMyShow(int n, int m) {
        this.n = n;
        this.m = m;
        rows = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            rows.add(new int[]{m});
        }
    }

    public int[] gather(int k, int maxRow) {
        for (int i = 0; i <= maxRow; i++) {
            if (rows.get(i)[0] >= k) {
                rows.get(i)[0] -= k;
                return new int[]{i, m - rows.get(i)[0] - k};
            }
        }
        return new int[0];
    }

    public boolean scatter(int k, int maxRow) {
        int count = 0;
        for (int i = 0; i <= maxRow; i++) {
            count += rows.get(i)[0];
            if (count >= k) {
                for (int j = 0; j <= maxRow; j++) {
                    if (rows.get(j)[0] > 0) {
                        rows.get(j)[0]--;
                        count--;
                        if (count == 0) break;
                    }
                }
                return true;
            }
        }
        return false;
    }
}
